INSERT INTO `productos` (`id`, `vendedor_id`, `categoria_id`, `nombre`, `descripcion`, `recomendacion`, `beneficios`, `valor`, `imagen`, `activo`, `creado_en`, `actualizado_en`) VALUES

(1, 1, 1,
 'Boldo + Clorofila y Menta',
 'Suplemento natural polivalente en presentación líquida que combina cinco poderosos extractos botánicos: boldo (Peumus boldus) para el soporte hepático y biliar, clorofila de origen vegetal con acción desintoxicante y alcalinizante, menta piperita para el alivio digestivo y el frescor interno, sábila (aloe vera) con propiedades regenerativas y emolientes para la mucosa gastrointestinal, y albahaca rica en antioxidantes naturales. Esta fórmula sinérgica actúa sobre el sistema digestivo, el hígado y la circulación linfática, promoviendo una depuración profunda y sostenida del organismo. Ideal para personas que buscan un apoyo natural en la desintoxicación diaria, especialmente después de períodos de alimentación poco saludable, consumo de alcohol u otras situaciones de sobrecarga hepática.',
 'Disolver una cucharada sopera (15 ml) en un vaso de agua tibia (200 ml) y consumir preferiblemente después de las comidas principales (almuerzo y cena). No exceder la dosis diaria indicada. Conservar refrigerado una vez abierto y consumir antes de 30 días. No recomendado para mujeres embarazadas o en lactancia sin supervisión médica.',
 '["Desintoxicación Natural: Estimula los órganos de eliminación (hígado, riñón, intestino) para expulsar toxinas acumuladas.", "Soporte Hepático: El boldo favorece la producción y el flujo de bilis, aliviando la carga del hígado.", "Digestión Saludable: La menta y la sábila calman la inflamación digestiva y reducen la sensación de pesadez.", "Purificación del Cuerpo: La clorofila alcaliniza el medio interno y ayuda a neutralizar radicales libres.", "Efecto Refrescante y Revitalizante: Proporciona sensación de ligereza y bienestar general tras cada toma."]',
 38000.00, 'img/productos/2/1_25_clorofila_menta.jpeg', 1, '2026-03-09 23:00:26', '2026-03-20 06:33:11'),

(2, 1, 1,
 'Citrato y Cloruro de Magnesio - Potasio',
 'Suplemento mineral avanzado de magnesio 4 en 1 que combina cuatro formas complementarias del mineral para garantizar una absorción óptima y una biodisponibilidad superior. Incluye citrato de magnesio (alta absorción, efecto relajante muscular y nervioso), cloruro de magnesio (depurativo celular y activador enzimático), glicinato de magnesio (forma quelada de fácil asimilación con efecto calmante) y malato de magnesio (favorece la producción energética a nivel celular). La adición de potasio potencia la regulación del equilibrio electrolítico y la función cardiovascular. Este complejo está formulado en cápsulas gastrorresistentes para asegurar la liberación en el intestino delgado, maximizando así su aprovechamiento. Especialmente indicado para personas con calambres frecuentes, insomnio, estrés crónico, hipertensión arterial leve o déficit mineral confirmado por análisis clínico.',
 'Tomar 1 cápsula al día preferiblemente con la comida principal (almuerzo) para mejorar la tolerancia gastrointestinal y la absorción. En períodos de mayor desgaste físico o estrés, se puede incrementar a 2 cápsulas diarias (mañana y noche), siempre con alimentos. No superar la dosis máxima indicada. Mantener fuera del alcance de menores de 12 años.',
 '["Función Muscular y Nerviosa: Regula la contracción muscular y la transmisión de impulsos nerviosos, previniendo calambres y espasmos.", "Regulación de la Presión Arterial: El potasio y el magnesio trabajan en sinergia para mantener la tensión arterial en rangos saludables.", "Salud Ósea: Participa en la fijación del calcio en los huesos y en la mineralización ósea.", "Alivio de Migrañas: Estudios clínicos asocian el déficit de magnesio con la cefalea tensional; su suplementación ayuda a reducir frecuencia e intensidad.", "Apoyo Digestivo: El magnesio actúa como cofactor de más de 300 reacciones enzimáticas, incluyendo las relacionadas con la motilidad intestinal."]',
 50000.00, 'img/productos/2/2_38_citrato.jpeg', 1, '2026-03-09 23:00:26', '2026-03-20 06:33:11'),

(3, 1, 1,
 'Vitamina E - 1.000 UI',
 'Suplemento dietario de alta concentración de alfa-tocoferol (Vitamina E natural d-alfa) en dosis de 1.000 UI por cápsula blanda de gelatina. La vitamina E es el principal antioxidante liposoluble del organismo, encargado de proteger las membranas celulares del daño oxidativo causado por los radicales libres generados por la contaminación ambiental, el tabaquismo, el estrés y el envejecimiento. A esta concentración terapéutica, actúa también como modulador del sistema inmunológico, antiagregante plaquetario suave y protector de la integridad de las paredes arteriales. Su presentación en cápsula blanda garantiza mayor estabilidad del principio activo y mejor absorción en presencia de lípidos dietéticos. Recomendado para adultos mayores de 18 años que buscan un apoyo antioxidante potente, cuidado de la piel desde adentro y protección cardiovascular.',
 'La dosis de 1.000 UI se administra preferiblemente una vez al día, acompañando una comida que contenga grasas saludables (aguacate, aceite de oliva, frutos secos) para optimizar su absorción, ya que es una vitamina liposoluble. No se recomienda su uso durante el embarazo sin supervisión médica ni en pacientes en tratamiento anticoagulante (warfarina) sin consultar al médico tratante, debido a su leve efecto antiagregante.',
 '["Antioxidante Potente: Neutraliza los radicales libres y protege las células del daño oxidativo, frenando el envejecimiento prematuro a nivel celular.", "Salud de la Piel: Promueve la síntesis de colágeno, mejora la hidratación cutánea y reduce la hiperpigmentación por exposición solar.", "Protección Cardiovascular: Inhibe la oxidación del colesterol LDL, reduce la adhesión plaquetaria y protege el endotelio vascular.", "Mejora de la Salud Ocular: Retrasa la progresión de la degeneración macular asociada a la edad (DMAE) y protege el cristalino.", "Apoyo al Sistema Inmunológico: Estimula la producción de linfocitos T y la respuesta inmune celular, especialmente en adultos mayores."]',
 52000.00, 'img/productos/2/3_40_vitamina_E.jpeg', 1, '2026-03-09 23:00:26', '2026-03-20 06:33:11'),

(4, 1, 1,
 'Duo de Bienestar Integral: Citrato de Magnesio + Vitamina E',
 'Combo terapéutico que fusiona en una sola presentación el Citrato de Magnesio en gomitas masticables junto con Vitamina E en forma de d-alfa tocoferol, diseñado para ofrecer una doble acción antioxidante, mineralizante y neuroprotectora. El citrato de magnesio en formato de gomita mejora la adherencia al tratamiento gracias a su sabor agradable y su rápida disolución, siendo especialmente útil para personas con dificultad para tragar cápsulas. Cada dosis aporta una cantidad precisa de magnesio elemental y vitamina E, calculada para cubrir los requerimientos diarios del adulto activo sin riesgo de superar los límites seguros. Esta combinación es especialmente indicada para deportistas, personas con alto nivel de estrés oxidativo, adultos mayores y mujeres en etapa de menopausia.',
 'Tomar 2 gomitas al día, preferiblemente después de una comida principal. Masticar bien antes de tragar. No exceder la dosis recomendada. Conservar en lugar fresco y seco, alejado de la luz solar directa. No apto para personas con intolerancia a la sacarosa o con restricción de azúcares simples sin consulta médica previa.',
 '["Antioxidante Potente: La vitamina E y el magnesio actúan en sinergia para contrarrestar el estrés oxidativo a nivel celular y tisular.", "Relajación Muscular: El magnesio regula la contracción-relajación muscular, aliviando calambres, tensión y rigidez post-ejercicio.", "Salud Ósea: El magnesio es cofactor esencial en la absorción del calcio y en la mineralización del tejido óseo.", "Mejora de la Salud Ocular: La vitamina E protege la mácula y el cristalino del daño oxidativo acumulado.", "Reduce el Estrés Oxidativo: La acción combinada de ambos nutrientes disminuye los marcadores inflamatorios y favorece la recuperación celular."]',
 55000.00, 'img/productos/2/4_40_magnecio+vitaminaE.jpeg', 1, '2026-03-09 23:00:27', '2026-03-20 06:33:11'),

(5, 1, 1,
 'Omega 3',
 'Suplemento de ácidos grasos omega-3 de cadena larga de alta pureza, obtenido mediante extracción molecular de aceite de pescado de aguas profundas (anchoveta y sardina del Pacífico Sur), con concentración certificada de EPA (ácido eicosapentaenoico) y DHA (ácido docosahexaenoico) por cápsula. Sometido a procesos de destilación molecular para eliminar metales pesados, dioxinas y PCBs, garantizando un producto libre de contaminantes. Los omega-3 son ácidos grasos poliinsaturados esenciales que el cuerpo humano no puede sintetizar por sí mismo y que desempeñan un papel crítico en la fluidez de las membranas celulares, la regulación de la inflamación sistémica, la función neurológica y la salud cardiovascular. Presentación: frascos con 60 cápsulas blandas con recubrimiento entérico para eliminar el retrogusto a pescado.',
 'La OMS recomienda entre 250 y 500 mg diarios de EPA+DHA para adultos sanos, pudiendo aumentarse hasta 2.000 mg bajo supervisión médica para condiciones como hipertrigliceridemia o inflamación crónica. Tomar preferiblemente con la comida principal para mejorar la absorción. En pacientes con tratamiento anticoagulante, consultar al médico antes de iniciar la suplementación.',
 '["Apoya la Salud Cerebral y Cognitiva: El DHA es el principal componente estructural del tejido cerebral; su aporte adecuado favorece la memoria, la concentración y la velocidad de procesamiento mental.", "Reduce la Inflamación Corporal: El EPA es precursor de eicosanoides antiinflamatorios que modulan la respuesta inmune y reducen la inflamación crónica de bajo grado.", "Mejora la Salud Cardiovascular: Disminuye los triglicéridos séricos, reduce la presión arterial leve y mejora la función endotelial.", "Mejora la Hidratación y Salud de la Piel: Fortalece la barrera lipídica epidérmica, reduciendo la sequedad, la descamación y la sensibilidad cutánea.", "Salud Ocular: El DHA constituye el 60% de los ácidos grasos del segmento externo de los fotorreceptores retinianos, siendo esencial para la agudeza visual."]',
 55000.00, 'img/productos/2/5_40_omega3.jpeg', 1, '2026-03-09 23:00:27', '2026-03-20 06:33:11'),

(6, 1, 1,
 'Ginkgo Biloba',
 'Extracto estandarizado de hojas de Ginkgo biloba (EGb 761®) en cápsulas, con un contenido garantizado del 24% de flavonoides glucósidos (ginkgoflavonglucósidos) y 6% de terpenoides (ginkgólidos A, B, C y bilobalido), que son los principios activos responsables de su eficacia clínica demostrada. El Ginkgo biloba es uno de los árboles más antiguos del planeta y su extracto ha sido objeto de cientos de estudios científicos que respaldan su acción vasodilatadora, antiagregante, neuroprotectora y antioxidante. Actúa mejorando la microcirculación cerebral y periférica al inhibir el Factor Activador de Plaquetas (PAF) y al dilatar los vasos sanguíneos, lo que se traduce en un mayor aporte de oxígeno y glucosa al tejido cerebral. Indicado especialmente en adultos mayores de 40 años con signos de deterioro cognitivo leve, acúfenos, vértigo de origen vascular o claudicación intermitente.',
 'No exceder la dosis diaria recomendada indicada en el envase (generalmente 120-240 mg de extracto seco al día, divididos en 2 tomas). Consultar con un profesional de la salud antes de iniciar el tratamiento, especialmente en pacientes con trastornos hemorrágicos, en tratamiento con anticoagulantes (warfarina, aspirina), antiepilépticos o inhibidores de la MAO. Requiere uso continuado de al menos 4-6 semanas para observar resultados.',
 '["Mejora el Flujo Sanguíneo Cerebral y Periférico: Actúa como vasodilatador y antiagregante plaquetario, aumentando la perfusión de oxígeno en el cerebro y las extremidades.", "Mejora la Memoria y la Concentración: Retrasa el deterioro cognitivo asociado al envejecimiento y mejora el rendimiento mental en tareas que requieren atención sostenida.", "Actúa como Potente Antioxidante: Los flavonoides del ginkgo neutralizan radicales libres y protegen las neuronas del daño oxidativo.", "Reduce la Fatiga Mental y el Estrés: Regula la respuesta al estrés al modular los niveles de cortisol y mejorar la adaptación neurológica.", "Alivio de Acúfenos y Vértigo: La mejora en la microcirculación del oído interno puede contribuir a reducir la intensidad de los acúfenos y los episodios de vértigo de origen vascular."]',
 45000.00, 'img/productos/2/6_32_ginkgo.jpeg', 1, '2026-03-09 23:00:27', '2026-03-20 06:33:11'),

(7, 1, 1,
 'ASHWAGANDHA KSM-66',
 'Extracto de raíz entera de Withania somnifera (ashwagandha) bajo el estándar patentado KSM-66®, reconocido mundialmente como el extracto de ashwagandha de espectro completo más investigado del mercado. Elaborado únicamente a partir de la raíz (no de hojas ni tallos), mediante un proceso de extracción acuoso sin solventes alcohólicos, respetando los principios de la medicina ayurvédica. Contiene una concentración mínima garantizada del 5% de withanólidos, los principios activos responsables de su acción adaptogénica, ansiolitica e inmunomoduladora. Cuenta con más de 20 estudios clínicos en humanos controlados con placebo que avalan su eficacia en la reducción del estrés percibido (escala PSS), la mejora de la calidad del sueño, el aumento de la testosterona en hombres y la mejora del rendimiento físico. Certificado USDA Organic, Non-GMO y Halal.',
 'Dosis de 300 a 600 mg de extracto KSM-66 al día, dividida en dos tomas iguales (mañana con el desayuno y noche con la cena), siempre con alimentos para mejorar la absorción y reducir la posibilidad de molestias estomacales. Para resultados óptimos, mantener la suplementación durante un mínimo de 8 semanas de forma continuada. No usar durante el embarazo ni la lactancia. Consultar al médico en caso de enfermedades autoinmunes, hipotiroidismo en tratamiento o sensibilidad a plantas de la familia Solanaceae.',
 '["Reduce el Estrés y el Cortisol: Clasificado como adaptógeno de tipo I, regula el eje HPA y reduce los niveles séricos de cortisol hasta un 27%, según estudios clínicos con KSM-66.", "Mejora del Sueño: Aumenta la calidad y la duración del sueño profundo (fase III y IV), favoreciendo la recuperación nocturna y reduciendo el insomnio por estrés.", "Rendimiento Físico y Mental: Incrementa la resistencia aeróbica (VO2 máx), la fuerza muscular y la velocidad de reacción cognitiva en adultos activos.", "Apoyo Hormonal: Eleva de forma natural los niveles de testosterona y DHEA en hombres, mejorando la vitalidad, la libido y la composición corporal.", "Neuroprotección y Bienestar Emocional: Los withanólidos tienen propiedades neuroprotectoras demostradas y contribuyen a reducir los síntomas de ansiedad y depresión leve."]',
 60000.00, 'img/productos/2/7_45_ksm-66.jpeg', 1, '2026-03-09 23:00:27', '2026-03-20 06:33:11'),

(8, 1, 1,
 'GLUCOSAMIN 1500 mg',
 'Suplemento articular de alta concentración con 1.500 mg de sulfato de glucosamina por dosis diaria, la forma más estudiada y biodisponible de glucosamina en el mercado farmacológico y nutricional. La glucosamina es un aminomonosacárido endógeno que el organismo utiliza como sustrato esencial para la biosíntesis del cartílago articular, el líquido sinovial, los tendones y los ligamentos. Con la edad, la producción endógena disminuye significativamente, lo que contribuye a la degradación del cartílago y al desarrollo de osteoartritis. La suplementación con sulfato de glucosamina en dosis de 1.500 mg/día ha demostrado en múltiples estudios randomizados (entre ellos el ensayo GAIT publicado en NEJM) reducir el dolor articular, frenar la progresión radiológica del estrechamiento del espacio articular y mejorar la función en pacientes con osteoartritis de rodilla de grado leve a moderado. Presentación: frasco con 60 cápsulas vegetales.',
 'Tomar dos cápsulas diarias preferiblemente con las comidas para minimizar posibles molestias gastrointestinales. El efecto terapéutico completo generalmente se observa tras 4 a 8 semanas de uso continuado. No usar en personas con alergia conocida a los mariscos (fuente habitual de glucosamina), con diabetes mellitus tipo 2 sin control glucémico estable, ni en embarazo o lactancia sin prescripción médica.',
 '["Salud Articular: Aporta el sustrato necesario para la regeneración del cartílago articular y la producción de proteoglicanos del líquido sinovial.", "Mejora la Elasticidad de la Piel: La glucosamina también participa en la síntesis de ácido hialurónico, contribuyendo a la hidratación y firmeza cutánea.", "Alivio del Dolor: Reduce el dolor articular crónico de forma comparable a los AINEs en ciertos subgrupos de pacientes con osteoartritis.", "Mejora la Hidratación Articular: Estimula la producción de líquido sinovial, lubricando las articulaciones y reduciendo la fricción.", "Mejora la Movilidad: Favorece el rango de movimiento articular al disminuir la inflamación y mejorar la integridad del tejido cartilaginoso."]',
 54000.00, 'img/productos/2/8_40_glucosamin.jpeg', 1, '2026-03-09 23:00:27', '2026-03-20 06:33:11'),

(9, 1, 1,
 'GAF-PLUS',
 'Suplemento multivitamínico y multimineral de base herbal en presentación líquida de alta biodisponibilidad, formulado con un complejo de vitaminas del grupo B (B1, B2, B3, B5, B6, B12), vitaminas C, D y E, más minerales clave como zinc, magnesio, hierro y manganeso, sinergizados con extractos de plantas medicinales (cola de caballo, ortiga verde, alfalfa y ginseng panax). Esta combinación integral está diseñada para corregir deficiencias nutricionales múltiples, frecuentes en personas con alimentación desequilibrada, adultos mayores, deportistas y mujeres en etapa reproductiva. La presentación líquida permite una absorción más rápida que las formas sólidas al no requerir proceso de disolución en el tracto gastrointestinal. Frasco de 500 ml con dosificador.',
 'Tomar una copa dosificadora (15 ml) dos veces al día, preferiblemente con el desayuno y con el almuerzo. Agitar bien antes de usar. Conservar refrigerado una vez abierto y consumir antes de 30 días. Evitar la administración simultánea con café, té o zumo de pomelo, ya que pueden interferir con la absorción de ciertos micronutrientes.',
 '["Huesos Fuertes: El complejo de vitamina D, calcio y magnesio soporta la mineralización y densidad ósea, previniendo la osteopenia.", "Articulaciones Flexibles: Los extractos de cola de caballo (rico en sílice orgánico) y ortiga favorecen la formación de colágeno y la elasticidad articular.", "Energía Vital: Las vitaminas del grupo B actúan como cofactores en el metabolismo energético celular (ciclo de Krebs), reduciendo la fatiga física y mental.", "Refuerzo Inmunológico: La vitamina C, el zinc y el ginseng modulan positivamente la respuesta inmune innata y adaptativa.", "Equilibrio Nutricional General: Cubre las necesidades básicas de micronutrientes en personas con alta demanda fisiológica o alimentación deficitaria."]',
 41000.00, 'img/productos/2/9_30_gaf-plus.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(10, 1, 1,
 'Salud de la Mujer',
 'Formulación fitoterapeútica en jarabe elaborada con una combinación de plantas medicinales de uso tradicional en la ginecología natural: agracejo (Berberis vulgaris), cimicífuga (Actaea racemosa), sauzgatillo (Vitex agnus-castus), manzanilla (Matricaria chamomilla) y jengibre (Zingiber officinale). Cada una de estas plantas ha sido seleccionada por su reconocida acción sobre el sistema hormonal femenino y el aparato reproductor. El sauzgatillo, en particular, actúa sobre el eje hipotálamo-hipofisario modulando los niveles de prolactina y favoreciendo el equilibrio entre estrógenos y progesterona. La manzanilla y el jengibre aportan propiedades antiespasmódicas, antiinflamatorias y analgésicas que alivian los síntomas del síndrome premenstrual y la dismenorrea. Presentación: jarabe en frasco de 250 ml.',
 'Tomar por vía oral 3 veces al día (mañana, tarde y noche), generalmente antes de las comidas principales, durante los días previos y durante el período menstrual, o según indicación del fabricante en el empaque. En casos de irregularidad del ciclo, se recomienda un tratamiento continuado de al menos 3 meses para observar resultados estables. No usar en embarazo. Consultar al médico en caso de fibromas uterinos u otras patologías ginecológicas diagnosticadas.',
 '["Desinflamante Femenino: Reduce la inflamación pélvica y el edema asociado al síndrome premenstrual mediante la acción de flavonoides y fitoestrógenos.", "Alivia los Cólicos Menstruales: Los espasmolíticos naturales relajan la musculatura uterina, reduciendo la intensidad y la duración del dolor menstrual.", "Disminuye el Flujo y las Molestias: Regula la intensidad del sangrado menstrual excesivo (menorragia) y reduce la inflamación y el malestar general del período."]',
 30000.00, 'img/productos/2/10_23_salud_de_la_mujer.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(11, 1, 1,
 'Vita Celebrina - Jarabe',
 'Suplemento nootrópico en jarabe de sabor agradable, formulado con un complejo de vitaminas y minerales especialmente seleccionados para el soporte de la función cognitiva, el sistema nervioso central y el rendimiento intelectual en niños en etapa escolar y adultos. Su fórmula incluye vitaminas del grupo B (especialmente B1-tiamina, B6-piridoxina y B12-cianocobalamina) esenciales para la síntesis de neurotransmisores (serotonina, dopamina, acetilcolina), vitamina C como cofactor antioxidante neuronal, zinc para la maduración cerebral, y extractos de plantas adaptogénicas como el ginseng y la lecitina de soja como fuente natural de fosfatidilcolina. La lecitina de soja es el principal precursor de la acetilcolina, el neurotransmisor del aprendizaje y la memoria. Indicado especialmente en períodos de alta exigencia académica, exámenes o situaciones de fatiga mental.',
 'Para niños mayores de 4 años y menores de 12: tomar 2 cucharaditas (10 ml) al día con el desayuno. Para adolescentes y adultos: tomar 2 cucharadas soperas (30 ml) con el desayuno. Agitar antes de usar. Conservar refrigerado una vez abierto y usar antes de 30 días. No administrar a niños menores de 4 años sin indicación médica.',
 '["Mejora la Memoria: Aporta los precursores necesarios para la síntesis de acetilcolina, neurotransmisor clave en los procesos de memorización y consolidación del aprendizaje.", "Aumenta la Concentración: Las vitaminas B6 y B12 modulan los niveles de homocisteína y favorecen la mielinización neuronal, mejorando la velocidad de procesamiento y el enfoque.", "Refuerza el Rendimiento Mental: La combinación de vitaminas del grupo B, vitamina C y adaptógenos reduce la fatiga mental y sostiene el rendimiento intelectual en jornadas largas.", "Apoya el Desarrollo Neurológico Infantil: Aporta nutrientes esenciales para la maduración del sistema nervioso en niños en período escolar.", "Bienestar General y Vitalidad: El aporte vitamínico y mineral integral combate la astenia y el decaimiento, mejorando el estado de ánimo y la motivación."]',
 40000.00, 'img/productos/2/11_28_vitacelebrina_jarabe.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(12, 1, 1,
 'Enervital - Jarabe',
 'Suplemento alimenticio multivitamínico en jarabe especialmente formulado para cubrir los requerimientos nutricionales específicos de niños en etapa de crecimiento (de 2 a 12 años). Enriquecido con un amplio espectro de vitaminas (A, C, D, E y complejo B completo), minerales esenciales para el desarrollo óseo y muscular (calcio, fósforo, zinc, hierro y magnesio), y aminoácidos de apoyo al crecimiento tisular. El hierro presente en su fórmula contribuye a la prevención de la anemia ferropénica, una de las deficiencias nutricionales más comunes en la infancia en países en desarrollo. La vitamina D y el calcio en proporciones balanceadas favorecen la mineralización ósea y el crecimiento estatural. El sabor agradable facilita la adherencia al tratamiento en población pediátrica.',
 'Tomar una medida (cuchara dosificadora incluida) 3 veces al día, preferiblemente con las comidas (desayuno, almuerzo y cena) para mejorar la absorción de los micronutrientes. Para niños menores de 2 años, consultar con el pediatra antes de iniciar la suplementación. Agitar bien antes de servir. Conservar refrigerado una vez abierto y consumir antes de 21 días.',
 '["Aporta Energía: El complejo vitamínico B actúa como coenzima en el metabolismo de los hidratos de carbono y las grasas, proporciona energía para las actividades físicas e intelectuales del niño.", "Refuerza las Defensas: Las vitaminas A, C, E y el zinc fortalecen el sistema inmunológico innato y adaptativo, reduciendo la frecuencia e intensidad de las infecciones respiratorias.", "Crecimiento Saludable: El calcio, el fósforo, la vitamina D y los aminoácidos esenciales proporcionan los nutrientes estructurales necesarios para el desarrollo óseo, muscular y neurológico durante la infancia."]',
 38000.00, 'img/productos/2/12_24_enervital.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(13, 1, 1,
 'NeurisZinc - Cápsulas',
 'Suplemento neuronutritivo en cápsulas formulado con una sinergia de nutrientes y extractos botánicos que actúan sobre el sistema nervioso central para mejorar la función cognitiva, reducir el estrés oxidativo neuronal y modular la respuesta al estrés y la ansiedad. Su composición incluye zinc quelado (picolinato de zinc) en dosis terapéutica, ginkgo biloba estandarizado, complejo de vitaminas B (B6, B9 y B12), L-teanina (aminoácido del té verde con efecto ansiolítico sin sedación) y magnesio glicinato. El zinc es un oligoelemento esencial para la síntesis de más de 300 enzimas, incluyendo las involucradas en la neurotransmisión glutamatérgica y la señalización neuronal. El déficit subclínico de zinc es especialmente frecuente en adultos con dietas restrictivas y se asocia con problemas de memoria, concentración y estado de ánimo. Presentación: frasco con 60 cápsulas vegetales.',
 'Posología indicada por el fabricante según presentación (generalmente 1-2 cápsulas al día con el desayuno o la cena). Para el efecto ansiolítico y de mejora del sueño, se puede tomar la dosis nocturna 1 hora antes de dormir. Evitar el consumo simultáneo con calcio o hierro, ya que compiten por los mismos transportores intestinales. No combinar con otros suplementos de zinc sin supervisión.',
 '["Apoyo a la Memoria: El zinc participa en la plasticidad sináptica y en la consolidación de la memoria a largo plazo; el ginkgo mejora la perfusión cerebral y la retención de información.", "Mejora la Concentración: La L-teanina promueve ondas cerebrales alfa asociadas con un estado de alerta relajada, favoreciendo el foco mental sin generar nerviosismo.", "Reduce el Estrés y la Ansiedad: La L-teanina, el magnesio y el zinc modulan el eje HPA y los receptores GABA/glutamato, reduciendo la ansiedad situacional y el estrés crónico.", "Función Neurológica Saludable: Las vitaminas B6, B9 y B12 son esenciales para la síntesis de serotonina, dopamina y noradrenalina, los neurotransmisores del bienestar emocional.", "Neuroprotección: La combinación antioxidante de zinc, vitamina E y ginkgo protege las neuronas del daño oxidativo y retrasa el deterioro cognitivo asociado a la edad."]',
 38000.00, 'img/productos/2/13_25_neurizinc.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(14, 1, 1,
 'GAF-PLUS OMEGA 3, 6, 9',
 'Suplemento en cápsulas blandas con una matriz lipídica de alta pureza que combina ácidos grasos omega-3 (EPA y DHA de aceite de pescado del Pacífico), omega-6 (ácido linoléico de aceite de onagra) y omega-9 (ácido oleico de aceite de oliva virgen extra), formulados en proporciones clínicamente estudiadas para maximizar su efecto antiinflamatorio, cardiovascular y dérmico. Esta triple acción de omegas aporta los precursores de eicosanoides antiinflamatorios y prostaglandinas que regulan desde la coagulación sanguínea hasta la permeabilidad epidérmica. La adición de omega-6 en forma de GLA (ácido gamma-linolénico) del aceite de onagra hace de este producto una opción especialmente valiosa para mujeres con síndrome premenstrual, piel seca o afecciones dermatológicas como eccema y psoriasis. Cada cápsula contiene vitamina E como antioxidante natural para preservar la estabilidad de los ácidos grasos.',
 'Tomar 2 cápsulas al día con las comidas (preferiblemente la comida principal del mediodía) para optimizar la absorción y minimizar el retrogusto. En personas con hipertrigliceridemia o inflamación articular crónica, se puede aumentar a 3 cápsulas bajo supervisión médica. Almacenar en lugar fresco y oscuro; el calor y la luz oxidan los ácidos grasos insaturados.',
 '["Piel Radiante y Elástica: El GLA del omega-6 y el DHA del omega-3 refuerzan la barrera lipídica cutánea, mejoran la hidratación transepidérmica y reducen la inflamación en pieles secas o con dermatitis.", "Equilibrio Electrolítico: Los ácidos grasos participan en la modulación de los canales iónicos de membrana y en la regulación de la presión osmótica celular.", "Reducción de la Inflamación: El EPA inhibe la vía de la ciclooxigenasa-2 (COX-2), reduciendo la producción de prostaglandinas proinflamatorias PGE2.", "Salud Cardiovascular y Cerebral: El DHA es esencial para la integridad estructural de las membranas de cardiomiocitos y neuronas; el omega-9 mejora el perfil lipídico reduciendo el colesterol LDL.", "Bienestar Femenino: El GLA del aceite de onagra ayuda a regular el ciclo hormonal y reduce los síntomas del síndrome premenstrual, incluyendo la mastodinia y la irritabilidad."]',
 55000.00, 'img/productos/2/14_40_gaf-plus_omega3.jpeg', 1, '2026-03-09 23:00:28', '2026-03-20 06:33:11'),

(15, 1, 1,
 'Colágeno Hidrolizado Healthy Life',
 'Suplemento de colágeno hidrolizado tipo I y III en cápsulas de gelatina, obtenido mediante hidrólisis enzimática controlada a partir de cuero vacuno libre de hormonas, lo que genera péptidos de bajo peso molecular (3.000-5.000 Da) con alta biodisponibilidad y capacidad de absorción intestinal demostrada. El colágeno representa aproximadamente el 30% de las proteínas totales del cuerpo humano y es el principal componente estructural de la piel, el cartílago articular, los huesos, los tendones, los ligamentos y la fascia muscular. A partir de los 25 años la síntesis endógena de colágeno disminuye un 1-1,5% anual, lo que se traduce progresivamente en arrugas, pérdida de elasticidad articular y reducción de la masa muscular. Los péptidos de colágeno hidrolizado estimulan los fibroblastos cutáneos y los condrocitos articulares para aumentar su propia producción de colágeno, elastina y ácido hialurónico. Frasco con 90 cápsulas.',
 'Consultar la etiqueta del producto para las instrucciones de uso personalizadas según el fabricante (generalmente 3-6 g de colágeno hidrolizado al día). Para maximizar la síntesis de colágeno endógeno, se recomienda acompañar la suplementación con una fuente de vitamina C (200-500 mg/día), ya que esta vitamina es cofactor esencial de la prolil y lisil hidroxilasa, enzimas clave en la formación de triple hélice del colágeno maduro.',
 '["Mejora la Salud de la Piel: Los péptidos de colágeno estimulan los fibroblastos, aumentando la densidad dérmica, la hidratación y la elasticidad cutánea, con reducción visible de arrugas finas tras 4-8 semanas de uso.", "Salud Articular y Cartílago: Los péptidos tipo II estimulan la producción de proteoglicanos en los condrocitos, regenerando el cartílago articular y reduciendo el dolor en osteoartritis.", "Cabello y Uñas Fuertes: La glicina y la prolina del colágeno son los aminoácidos estructurales de la queratina que forma el cabello y las uñas, mejorando su grosor y resistencia.", "Soporte Muscular: La glicina y la arginina del colágeno son precursoras de la creatina muscular, favoreciendo la recuperación y el mantenimiento de la masa magra.", "Bienestar General: La gelatina producida por la digestión del colágeno actúa como prebiótico suave, mejorando la integridad de la mucosa intestinal."]',
 50000.00, 'img/productos/2/15_35_colageno_hidrolizado.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(16, 1, 1,
 'Vitamina D3 Healthful Life',
 'Suplemento de colecalciferol (Vitamina D3) en cápsulas blandas de 4.000 UI (100 mcg), la forma más biodisponible y activa de la vitamina D. A diferencia del ergocalciferol (D2) de origen vegetal, el colecalciferol (D3) de origen animal eleva los niveles séricos de 25(OH)D de forma significativamente más efectiva y sostenida. La vitamina D3 es en realidad una prohormona que, tras ser activada en el hígado (25-hidroxilación) y el riñón (1-alfa-hidroxilación), se convierte en calcitriol, su forma activa que regula la expresión de más de 2.000 genes en el organismo. Su acción trasciende el metabolismo óseo: modula el sistema inmunológico, regula la diferenciación celular, influye en la síntesis de serotonina y actúa como factor de transcripción para genes relacionados con la inflamación. Estudios epidemiológicos asocian el déficit de vitamina D (niveles séricos < 30 ng/mL) con mayor riesgo de infecciones respiratorias, diabetes tipo 2, enfermedades autoinmunes y depresión estacional.',
 'Ingerir 1 cápsula al día con una comida principal que contenga grasas para mejorar la absorción (vitamina liposoluble). La dosis de 4.000 UI está indicada para corrección de insuficiencia o deficiencia confirmada analíticamente. Para mantenimiento en personas con niveles suficientes, se puede considerar 1.000-2.000 UI/día. Consultar al médico antes de usar dosis superiores a 4.000 UI/día de forma crónica. No usar en hipercalcemia o sarcoidosis sin supervisión especializada.',
 '["Apoyo al Sistema Inmunitario: El calcitriol activa los linfocitos T citotóxicos y los macrófagos, y estimula la producción de péptidos antimicrobianos como la catelicidina.", "Huesos y Dientes Fuertes: Regula la absorción intestinal de calcio y fósforo y activa la osteocalcina, proteína clave en la mineralización ósea.", "Mejora el Estado de Ánimo y la Energía: La vitamina D regula la síntesis de serotonina en el cerebro; su déficit se asocia con síntomas depresivos, fatiga crónica y trastorno afectivo estacional.", "Salud Cardiovascular: Niveles adecuados de vitamina D se asocian con menor riesgo de hipertensión arterial, infarto de miocardio y accidente cerebrovascular.", "Regulación Hormonal y Antiinflamatoria: Modula el sistema renina-angiotensina y reduce la expresión de citoquinas proinflamatorias (IL-6, TNF-alfa)."]',
 45000.00, 'img/productos/2/16_30_vitaminaD3.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(17, 1, 1,
 'Vitamina C 1.000mg Healthful Life',
 'Suplemento de ácido L-ascórbico de alta concentración (1.000 mg por cápsula) en forma tamponada (ascorbato cálcico) para reducir la acidez gástrica, combinado con zinc quelado (10 mg) en forma de gluconato de zinc para potenciar la respuesta inmunológica. La vitamina C es el principal antioxidante hidrosoluble del organismo y un cofactor enzimático indispensable en más de 15 reacciones bioquímicas fundamentales, incluyendo la síntesis de colágeno, la biosíntesis de carnitina (transporte de ácidos grasos a las mitocondrias), la absorción de hierro no hémico y la síntesis de catecolaminas (adrenalina, noradrenalina). A dosis de 1.000 mg, la vitamina C alcanza sus efectos inmunomoduladores, antivirales y antioxidantes más pronunciados, siendo especialmente útil durante el invierno, períodos de estrés crónico o recuperación post-infecciosa.',
 'Tomar 1 cápsula al día, preferiblemente con alimentos para mejorar la tolerancia gástrica. La forma tamponada minimiza la irritación del esófago y el estómago que pueden producir dosis altas de ácido ascórbico estándar. En caso de infección activa o exposición elevada a radicales libres (fumadores, deportistas de alta intensidad), se puede aumentar temporalmente a 2 cápsulas bajo supervisión. Las dosis superiores a 2.000 mg/día de forma crónica pueden causar diarrea osmótica.',
 '["Refuerzo Inmunológico: Estimula la producción y la función de linfocitos, neutrófilos y células NK; reduce la duración e intensidad de los episodios de resfriado común en un 14% según metaanálisis.", "Protección Antioxidante: Neutraliza los radicales libres en medios acuosos intracelulares y regenera la vitamina E oxidada, amplificando la protección antioxidante global.", "Piel Saludable y Cicatrización: Es cofactor de la prolil y lisil hidroxilasa (síntesis de colágeno), acelerando la cicatrización de heridas y mejorando la firmeza y luminosidad cutánea.", "Más Energía: La síntesis de carnitina dependiente de vitamina C es esencial para la beta-oxidación de ácidos grasos en las mitocondrias, reduciendo la fatiga muscular.", "Absorción de Hierro: Convierte el hierro no hémico (hierro vegetal) a su forma ferrosa, aumentando su biodisponibilidad hasta en un 67%."]',
 40000.00, 'img/productos/2/17_28_vitaminaC_capsulas.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(18, 1, 1,
 'Expectorante Pulmonar Plus Bronco Dilatador',
 'Jarabe expectorante y broncodilatador de acción dual formulado con una combinación de principios activos mucolíticos (para licuar y fluidificar las secreciones bronquiales) y broncodilatadores naturales (para relajar la musculatura lisa bronquial y aumentar el diámetro de las vías respiratorias). Entre sus componentes activos habituales se encuentran extractos de eucalipto (Eucalyptus globulus), guaifenesin o guaiaco como agente mucolítico y fluidificante, miel de abeja como demulcente y antiséptico local, timol como antiséptico de las vías respiratorias y extracto de amapola californiana con propiedades antitusígenas suaves. Esta fórmula es especialmente indicada en cuadros de tos productiva con hipersecreción bronquial, bronquitis aguda, gripe con afectación de vías aéreas inferiores, asma leve con component secretor y procesos catarrales en niños y adultos.',
 'La dosis varía según la edad: en adultos, generalmente 15-20 ml (1 medida) cada 6-8 horas; en niños de 6 a 12 años, 7,5-10 ml cada 6-8 horas. Verificar siempre las indicaciones específicas del fabricante en el empaque, ya que pueden variar según la concentración del producto. Tomar con abundante agua para potenciar el efecto mucolítico. En caso de tos crónica persistente de más de 2 semanas, fiebre alta o sospecha de neumonía, consultar al médico.',
 '["Reduce la Tos y Expulsa las Flemas: Los agentes mucolíticos reducen la viscosidad del moco bronquial y estimulan el movimiento ciliar, facilitando su expulsión.", "Dilata los Bronquios: Los principios broncodilatadores (eucaliptol y otros terpenoides) relajan la musculatura lisa bronquial, aumentando el calibre de las vías aéreas y reduciendo la resistencia al flujo aéreo.", "Ayuda a Respirar Mejor: La combinación de broncodilatación y expectoración reduce la sensación de opresión torácica y mejora la saturación de oxígeno.", "Alivia la Congestión: El timol y el eucalipto tienen acción descongestionante de la mucosa nasofaríngea, aliviando la sensación de nariz tapada asociada al catarro.", "Antiséptico Natural: El timol y la miel inhiben el crecimiento bacteriano en la mucosa bronquial, reduciendo el riesgo de sobreinfección bacteriana."]',
 36000.00, 'img/productos/2/18_25_pulmonar.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(19, 1, 1,
 'Calostro Bovino Factor de Transferencia Omega 3, 6, 9',
 'Alimento funcional en polvo (tarro de 600 g, sabor vainilla) elaborado con calostro bovino liofilizado de primera ordeña (obtenido en las primeras 6 horas post-parto), enriquecido con proteína de suero de leche (whey protein), ácidos grasos esenciales omega-3 (DHA+EPA), omega-6 (GLA) y omega-9 (ácido oleico), calcio y magnesio. El calostro bovino es el fluido producido por la glándula mamaria bovina inmediatamente tras el parto y es la fuente natural más rica de factores de transferencia inmunológica, incluyendo inmunoglobulinas (IgG, IgA secretora, IgM), lactoferrina, lisozima, factores de crecimiento (IGF-1, TGF-beta) y citoquinas reguladoras. Los factores de transferencia son pequeñas moléculas de información inmune que educan y moderan al sistema inmunológico del receptor, representando una estrategia inmunomoduladora única. La adición de omegas y minerales convierte este producto en un suplemento completo e integral.',
 'Disolver 1-2 cucharadas rasas (20-30 g) en un vaso de agua, jugo o leche, una o dos veces al día. Para maximizar la absorción de las inmunoglobulinas y los factores de crecimiento, se sugiere tomarlo en ayunas o 30 minutos antes de la comida principal. No debe ser consumido por personas con alergia conocida a la proteína de la leche de vaca (caseína o lactoalbúmina). En embarazo y lactancia, consultar al médico. Es un suplemento dietario y no reemplaza una alimentación equilibrada.',
 '["Refuerza el Sistema Inmunológico: Las inmunoglobulinas bovinas (especialmente IgG) y los factores de transferencia educan y moderan el sistema inmune, siendo especialmente útil en personas con inmunodeficiencias relativas.", "Mejora la Salud Intestinal: La lactoferrina y las inmunoglobulinas secretoras (IgA) protegen la mucosa intestinal, regulan la microbiota y reducen la permeabilidad intestinal.", "Fuente de Omega 3, 6 y 9: Los ácidos grasos esenciales añadidos apoyan la salud cardiovascular, cerebral y cutánea, complementando el perfil nutricional del producto.", "Aporta Calcio y Magnesio: En proporciones sinérgicas para la mineralización ósea, la función muscular y la conducción nerviosa.", "Soporte en Recuperación y Rendimiento: El IGF-1 y los factores de crecimiento del calostro favorecen la recuperación muscular post-ejercicio y el mantenimiento de la masa magra."]',
 50000.00, 'img/productos/2/19_35_calostro.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(20, 1, 1,
 'Niños Aptmax',
 'Alimento en polvo especializado para niños en etapa de crecimiento (2-12 años), formulado a base de proteína de soya de alta calidad (con perfil completo de aminoácidos esenciales), concentrado de proteína de suero de leche (whey), calcio de alta biodisponibilidad, magnesio, vitaminas del grupo B y vitaminas A, C y D, con un sabor agradable de vainilla-fresa que facilita la adherencia en población infantil. Su composición está diseñada para complementar la alimentación en niños con bajo apetito, picky eaters, niños en recuperación nutricional o con alta demanda energética por actividad física deportiva. La proteína de suero de leche aporta leucina, el aminoácido activador de la síntesis proteica muscular, mientras que la proteína de soya aporta isoflavonas con ligero efecto inmunomodulador. Sin azúcares añadidos, endulzado con sucralosa.',
 'Seguir las instrucciones de preparación indicadas en el envase para determinar la porción adecuada según la edad y el peso del niño. Generalmente, disolver 2-3 cucharadas rasas en 200 ml de leche fría o tibia y mezclar bien. Puede usarse como reemplazo de merienda o como complemento nutritivo post-entrenamiento deportivo. No usar como sustituto de comidas principales en menores de 4 años sin indicación pediátrica.',
 '["Crecimiento Muscular: El aporte proteico de alta calidad (PDCAAS superior al de la proteína de soya aislada) proporciona todos los aminoácidos esenciales para el desarrollo de la masa muscular.", "Desarrollo Cognitivo: Las vitaminas del grupo B y el calcio son nutrientes esenciales para la mielinización neuronal y el desarrollo cognitivo en la infancia.", "Energía Sostenida: La combinación de proteínas de digestión lenta (soya) y rápida (whey) asegura un aporte energético progresivo y estable durante varias horas.", "Bienestar General: La matriz vitamínica y mineral completa apoya el sistema inmunológico, el desarrollo óseo y el equilibrio nutricional general del niño en crecimiento."]',
 42000.00, 'img/productos/2/20_30_aptmaxNiño.jpeg', 1, '2026-03-09 23:00:29', '2026-03-20 06:33:11'),

(21, 1, 1,
 'Citrato de Magnesio + Colágeno Hidrolizado',
 'Suplemento en polvo de sabor vainilla que combina en una sola toma el citrato de magnesio en su forma más soluble y biodisponible con colágeno hidrolizado tipo I y III (péptidos de bajo peso molecular obtenidos de piel bovina libre de hormonas) y calcio elemental aportado como carbonato cálcico. Esta tríada de nutrientes estructurales trabaja de forma sinérgica: el magnesio activa las enzimas prolil y lisil hidroxilasa necesarias para la síntesis de colágeno maduro; el calcio proporciona el mineral esencial para la mineralización ósea; y los péptidos de colágeno estimulan directamente los fibroblastos y condrocitos para producir más matriz extracelular. La presentación en polvo soluble permite una absorción más rápida que las formas sólidas y facilita la personalización de la dosis. Especialmente indicado para mujeres en etapa de menopausia, adultos mayores y deportistas.',
 'Disolver la porción indicada en el envase (generalmente 15-20 g) en un vaso de agua, leche o bebida vegetal favorita. Se puede tomar fría o tibia. Preferiblemente consumir en la mañana, en ayunas o con el desayuno. Para maximizar los beneficios en la síntesis de colágeno, se recomienda acompañar con vitamina C (al menos 200 mg/día). Evitar mezclar con bebidas muy calientes (>70°C) que puedan desnaturalizar los péptidos.',
 '["Salud Ósea y Dental: El calcio, el magnesio y los péptidos de colágeno forman la matriz orgánica e inorgánica del hueso, mejorando la densidad mineral ósea y reduciendo el riesgo de osteoporosis.", "Apoyo Articular y Muscular: El colágeno hidrolizado tipo II nutre el cartílago articular; el magnesio reduce los calambres y espasmos musculares.", "Cuidado de la Piel y el Cabello: Los péptidos de colágeno estimulan la producción de elastina y ácido hialurónico, mejorando la hidratación, la firmeza y la textura cutánea.", "Alivio de la Fatiga: El magnesio participa en la síntesis de ATP (la moneda energética celular), reduciendo la sensación de cansancio físico y mental.", "Función Muscular Normal: El magnesio regula la contracción y relajación muscular mediante el control del flujo de calcio a través de las membranas de las células musculares."]',
 50000.00, 'img/productos/2/21_35_citrato_de_magnecio.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(22, 1, 1,
 'Vitacerebrina Francesa',
 'Suplemento nootrópico de origen francés en presentación combinada de 20 tablecaps (cápsulas-tabletas) y 10 ampolletas bebibles, diseñado para un tratamiento completo e intensivo de soporte cognitivo, cardiovascular y antioxidante. La presentación dual (sólido + líquido) permite una liberación bifásica: las tablecaps aportan nutrientes de liberación sostenida (vitaminas B12, B6, B9, vitamina E, zinc y selenio) mientras que las ampolletas, al ser de administración directa sublingual o bebible, ofrecen una absorción rápida de extractos de ginkgo biloba, ginseng panax, coenzima Q10 y fosfatidilserina. La fosfatidilserina es un fosfolípido componente de las membranas neuronales cuyo declive en concentración está directamente relacionado con el deterioro cognitivo; su suplementación está respaldada por la FDA (declaración de salud calificada) para reducir el riesgo de disfunción cognitiva. Elaborado bajo estándares farmacéuticos franceses (GMP).',
 'El empaque contiene 20 tablecaps y 10 ampolletas diseñadas para un ciclo completo de tratamiento. Seguir el protocolo indicado en el empaque (generalmente 1 tablecap + 1 ampolleta al día durante los primeros 10 días, luego solo tablecaps). Para el efecto nootrópico completo, se recomienda completar el ciclo sin interrupciones. Conservar las ampolletas en lugar fresco y las tablecaps en lugar seco, alejado de la humedad.',
 '["Apoyo Cognitivo: La fosfatidilserina, el ginkgo y el ginseng mejoran la transmisión sináptica, la velocidad de procesamiento y la memoria de trabajo.", "Salud Cardiovascular: La coenzima Q10 protege el miocardio del estrés oxidativo y mejora la eficiencia energética del músculo cardíaco.", "Energía Mental: El complejo vitamínico B (especialmente B12) y el ginseng reducen la fatiga mental y mejoran la resistencia al estrés cognitivo.", "Protección Antioxidante: El selenio, la vitamina E y la CoQ10 neutralizan los radicales libres a nivel cerebral y cardiovascular, protegiendo el ADN mitocondrial.", "Síntesis de Neurotransmisores: Las vitaminas B6 y B12 son cofactores imprescindibles en la biosíntesis de serotonina, dopamina y acetilcolina."]',
 38000.00, 'img/productos/2/22_25_VitacelebrinaFrancesa.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(23, 1, 1,
 'Barrido Arterio Venoso',
 'Suplemento dietario sin azúcar añadida, formulado con extractos naturales y nutrientes específicamente seleccionados para la salud del sistema circulatorio arterial y venoso, siendo apto para personas con diabetes mellitus tipo 2. Su composición incluye niacina (vitamina B3) en forma de nicotinamida con efecto vasodilatador y regulador del colesterol HDL, extracto de ajo negro fermentado (con mayor concentración de S-alilcisteína que el ajo crudo), arándano azul (Vaccinium myrtillus) rico en antocianinas con acción protectora sobre la pared vascular, coenzima Q10 en forma de ubiquinol (forma reducida de mayor absorción), omega-3 de cadena larga y vitamina K2 (menaquinona MK-7) para el correcto depósito del calcio en los huesos y no en las arterias. Esta fórmula integral actúa sobre múltiples mecanismos de la aterosclerosis: oxidación del LDL, inflamación endotelial, formación de placa y rigidez arterial.',
 'Seguir las indicaciones del envase. Generalmente 1 o 2 cápsulas diarias, con las comidas, para mejorar la absorción de los ingredientes liposolubles (ubiquinol, omega-3, vitamina K2). En pacientes con tratamiento anticoagulante (warfarina) no usar sin consulta médica, ya que la vitamina K2 puede interferir con el INR. Mantener uso continuado de al menos 2-3 meses para observar cambios en el perfil lipídico.',
 '["Limpieza Arterial: Los flavonoides del arándano y el ajo negro inhiben la oxidación del LDL y la adhesión de monocitos al endotelio, reduciendo la formación de placa aterosclerótica.", "Control de Lípidos: La niacina eleva el colesterol HDL (colesterol bueno) hasta en un 30% y reduce los triglicéridos; el omega-3 disminuye la síntesis hepática de VLDL.", "Fortalecimiento Vascular: Las antocianinas del arándano refuerzan las paredes de capilares, arteriolas y venas, mejorando su elasticidad y reduciendo la fragilidad vascular.", "Mejora del Flujo Sanguíneo: La CoQ10 y el ajo negro mejoran la función endotelial y la vasodilatación dependiente del óxido nítrico (NO).", "Salud Cardiovascular Integral: Sin azúcar añadida, siendo seguro para personas con diabetes; la vitamina K2 dirige el calcio a los huesos y lo aleja de las arterias."]',
 39000.00, 'img/productos/2/23_25_barrido.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(24, 1, 1,
 'Combo Bienestar y Salud Digestiva (Lax Colon + Max Colon)',
 'Solución integral para el bienestar del colon que combina dos productos de acción complementaria: Lax Colon, un depurativo colónico formulado con extractos de cáscara sagrada (Rhamnus purshiana), sen (Cassia angustifolia), aloe vera y semilla de lino que estimula la peristalsis intestinal y facilita la evacuación en el estreñimiento crónico; y Max Colon, una fibra soluble e insoluble de alta densidad con psyllium husk, inulina (prebiótico que alimenta la microbiota beneficiosa), glucomanano de konjac y pectina de manzana, que forma un gel en el intestino que atrapa el colesterol, los azúcares y las grasas de la dieta. Juntos actúan en las dos fases del proceso depurativo: Lax Colon limpia el intestino y Max Colon regenera y protege su mucosa mientras regula el tránsito y el perfil metabólico. Combo presentado por separado para dosificación independiente.',
 'Lax Colon: seguir las indicaciones del envase (generalmente 1-2 cápsulas antes de dormir, solo por periodos cortos de 7-10 días). Max Colon: disolver 1 medida en un vaso grande de agua (300 ml) y beber inmediatamente antes o durante las comidas principales. Es fundamental consumir abundante agua durante el uso de fibra para evitar obstrucción intestinal. No usar Lax Colon de forma crónica por más de 10 días sin indicación médica (riesgo de dependencia laxante). Contraindicado en síndrome de intestino irritable agudo o enfermedad inflamatoria intestinal activa.',
 '["Limpieza Profunda del Sistema Digestivo: Lax Colon estimula la eliminación de residuos acumulados en el intestino grueso, eliminando las heces retenidas y las toxinas asociadas.", "Combate el Estreñimiento: La combinación de principios antracénicos y fibras solubles normaliza el tránsito intestinal y la consistencia de las deposiciones.", "Reductor de Peso Natural: El glucomanano y la inulina de Max Colon generan sensación de saciedad, reducen la absorción de calorías de la grasa y el azúcar.", "Regula el Colesterol y el Azúcar: La pectina y el psyllium forman geles viscosos en el intestino que reducen la reabsorción del colesterol biliar y ralentizan la absorción de glucosa post-prandial.", "Contiene 10 Extractos Naturales: La fórmula dual aprovecha la sinergia de diez ingredientes botánicos que actúan en diferentes segmentos del tracto digestivo para una depuración completa."]',
 78000.00, 'img/productos/2/24_50_par_laxcolon_y_Maxcolon.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(25, 1, 1,
 'Colágeno Hidrolizado + Biotina con Magnesio',
 'Suplemento líquido concentrado de 375 ml que reúne en una sola fórmula avanzada el colágeno hidrolizado de bajo peso molecular (péptidos tipo I y III de origen bovino), la biotina (vitamina B7 o H) en dosis funcional, el magnesio elemental en forma de citrato y un complejo vitamínico complementario (vitaminas C, E, B6 y B12). La biotina es una vitamina esencial para la síntesis de la queratina, la proteína estructural principal del cabello, las uñas y la capa más externa de la piel (epidermis), siendo su déficit una causa directa y tratable de caída del cabello, uñas quebradizas y dermatitis seborreica. La combinación con colágeno hidrolizado aporta los aminoácidos específicos (glicina, prolina e hidroxiprolina) que el folículo piloso y los queratinocitos necesitan para producir fibras de queratina resistentes. El magnesio en citrato actúa como cofactor enzimático en la síntesis de queratina y colágeno.',
 'Seguir las instrucciones del envase, preferiblemente tomar en la mañana antes del desayuno o con una comida ligera para maximizar la absorción en ayunas. Agitar bien antes de usar. Conservar refrigerado una vez abierto y consumir en los 30 días siguientes. Para resultados visibles en cabello y uñas, mantener el uso continuado durante 8-12 semanas.',
 '["Salud de la Piel: Los péptidos de colágeno y la biotina estimulan la renovación celular dérmica, mejorando la elasticidad, la hidratación y la luminosidad cutánea.", "Fortalece el Cabello: La biotina y la glicina del colágeno son los nutrientes estructurales primarios del folículo piloso; su aporte combinado reduce la caída, mejora el grosor y da brillo al cabello.", "Uñas Fuertes: La biotina aumenta el grosor de la placa ungueal en un 25% según estudios clínicos, reduciendo la fragilidad, las estrías longitudinales y la descamación.", "Bienestar Articular: Los péptidos de colágeno tipo II y el magnesio apoyan la regeneración del cartílago articular y reducen el dolor de articulaciones.", "Soporte Inmune: La vitamina C y la vitamina B12 del complejo vitamínico fortalecen las defensas y contribuyen al metabolismo energético celular."]',
 38000.00, 'img/productos/2/25_25_colageno_biotina.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(26, 1, 1,
 'Vino Cerebral Tónico Reconstituyente',
 'Tónico cerebral reconstituyente de 500 ml elaborado a base de extractos de plantas nootrópicas y adaptogénicas de reconocida eficacia clínica: Ginkgo biloba (EGB 761, 24% flavonoides, 6% terpenoides) para la microcirculación cerebral; Ginseng panax (7% ginsenósidos) como adaptógeno y estimulante cognitivo; Maca andina (Lepidium meyenii) para la energía y el equilibrio hormonal; Brahmi (Bacopa monnieri, 20% bacósidos) para la memoria y el aprendizaje; Rhodiola rosea (3% rosavinas, 1% salidrosida) para el rendimiento mental bajo estrés. Complementado con vitaminas del grupo B (B1, B6, B12) y vitamina C como cofactores neuroprotectores. Esta fórmula multi-extracto está especialmente indicada para profesionales con alta demanda cognitiva, estudiantes universitarios, adultos mayores con deterioro cognitivo leve y personas que experimentan fatiga mental o niebla cerebral (brain fog).',
 'Una copa dosificadora (30 ml) al día, preferiblemente con el desayuno para aprovechar el efecto estimulante cognitivo durante las horas de mayor actividad mental. No consumir en la noche si se observa dificultad para conciliar el sueño. Agitar antes de usar. Conservar refrigerado una vez abierto. No apto para menores de 18 años, mujeres embarazadas ni personas en tratamiento con anticoagulantes sin supervisión médica.',
 '["Apoyo a la Memoria y Concentración: El Ginkgo biloba, el Ginseng y la Bacopa monnieri actúan en sinergia para mejorar la memoria episódica, la memoria de trabajo y la velocidad de procesamiento de información.", "Salud Cardiovascular y Cerebral: El Ginkgo y la Rhodiola mejoran la microcirculación y la eficiencia energética del músculo cardíaco y del tejido cerebral.", "Energía y Vitalidad: La Maca andina y el Ginseng panax elevan los niveles de energía física y mental sin producir el rebote típico de los estimulantes sintéticos.", "Rendimiento Mental Bajo Estrés: La Rhodiola rosea es adaptógena de tipo II; reduce el cortisol y mejora el rendimiento cognitivo en situaciones de estrés agudo.", "Equilibrio y Adaptógeno: La combinación de adaptógenos (Ginseng, Maca, Rhodiola) y nootrópicos (Ginkgo, Brahmi) modula la respuesta al estrés crónico y mantiene el equilibrio neuro-endocrino."]',
 36000.00, 'img/productos/2/26_25_Vino_celebral.jpeg', 1, '2026-03-09 23:00:30', '2026-03-20 06:33:11'),

(27, 1, 1,
 'Artrin Natural (Original Cubano)',
 'Producto natural de origen cubano presentado en 25 grageas, formulado con principios activos de origen vegetal utilizados en la medicina tradicional cubana y latinoamericana para el manejo coadyuvante de los procesos degenerativos articulares. Su fórmula incluye extractos de ortiga verde (Urtica dioica) con propiedades antiinflamatorias mediadas por la inhibición de NF-kB, extracto de cola de caballo (Equisetum arvense) rico en sílice orgánico para la síntesis de colágeno y la resistencia del tejido conectivo, garra del diablo (Harpagophytum procumbens) con harpagosiósidos como principio activo de acción analgésica y antiinflamatoria comparable a algunos AINEs, cúrcuma (Curcuma longa) como antiinflamatorio natural y antioxidante, y boswelia serrata como inhibidor selectivo de la 5-lipoxigenasa (5-LOX). Esta fórmula actúa sobre los principales mecanismos patogénicos de la osteoartritis y las artropatías degenerativas.',
 'Consultar a un médico antes de su uso, especialmente en personas con patologías articulares diagnosticadas que estén bajo tratamiento farmacológico. La dosis habitual para este tipo de preparados es de 1-2 grageas con las comidas. El efecto antiinflamatorio y analgésico puede requerir 2-4 semanas de uso continuado para manifestarse plenamente. No usar en combinación con anticoagulantes orales sin supervisión médica.',
 '["Tratamiento Articular Coadyuvante: Los harpagosiósidos de la garra del diablo y los curcuminoides de la cúrcuma reducen la inflamación sinovial y el daño oxidativo en las articulaciones.", "Reducción del Dolor: La combinación de antiinflamatorios naturales (boswelia, cúrcuma, garra del diablo) produce alivio del dolor articular crónico con mejor tolerabilidad gastrointestinal que los AINEs.", "Alivio Lumbar: El extracto de ortiga verde y la cola de caballo reducen la inflamación en los discos intervertebrales y mejoran la movilidad lumbar.", "Propiedades Regenerativas: El sílice orgánico de la cola de caballo estimula la síntesis de colágeno tipo I en tendones, ligamentos y cartílagos, favoreciendo la regeneración del tejido conectivo.", "Tolerabilidad Natural: Al ser un producto enteramente de origen vegetal, tiene un perfil de efectos secundarios significativamente más favorable que los antiinflamatorios no esteroides convencionales."]',
 31000.00, 'img/productos/2/27_20_artrin.jpeg', 1, '2026-03-09 23:00:31', '2026-03-20 06:33:11'),

(28, 1, 1,
 'Ajo ROGOFF Garli (Improfarme)',
 'Tabletas recubiertas entéricas de alta concentración que combinan extracto de ajo envejecido (Allium sativum) estandarizado en S-alilcisteína, perejil (Petroselinum crispum) como neutralizador del olor del ajo y fuente de vitamina C y clorofila, aceite esencial de limón con propiedades antisépticas y depurativas, y un complejo vitamínico antioxidante (vitaminas A, C y E). El recubrimiento entérico garantiza que las tabletas se disuelvan en el intestino delgado (no en el estómago), preservando los compuestos organosulfurados del ajo (alicina y sus derivados) y eliminando completamente el mal aliento. El ajo envejecido es la forma más estudiada de ajo en el contexto cardiovascular, con más de 700 publicaciones científicas que avalan su capacidad para reducir la presión arterial, el colesterol LDL, la agregación plaquetaria y la inflamación sistémica. El frasco contiene 180 tabletas para un tratamiento de 2-6 meses.',
 'Seguir la dosis diaria indicada en el empaque (generalmente 1-3 tabletas al día con las comidas, según concentración del extracto). El recubrimiento entérico hace que sea imprescindible tragarlas enteras, sin masticarlas ni partirlas. Para resultados cardiovasculares óptimos, mantener el tratamiento continuado durante al menos 3 meses. Consultar al médico en caso de tratamiento anticoagulante.',
 '["Salud Cardiovascular: La S-alilcisteína del ajo envejecido inhibe la enzima HMG-CoA reductasa (igual mecanismo que las estatinas), reduciendo la síntesis hepática de colesterol LDL.", "Refuerzo Inmunitario: Los compuestos organosulfurados del ajo estimulan la actividad de las células NK y de los macrófagos, potenciando la respuesta inmune innata.", "Acción Antioxidante: El ajo envejecido tiene una capacidad antioxidante ORAC superior al ajo crudo; el complejo vitamínico (A, C, E) amplifica esta protección.", "Efecto Depurativo: La combinación de ajo, perejil y limón estimula la diuresis, la función hepática y la eliminación de toxinas liposolubles.", "Sin Mal Aliento: El recubrimiento entérico y el perejil garantizan que los compuestos volátiles del ajo se liberen en el intestino, no en la boca ni el estómago."]',
 31000.00, 'img/productos/2/28_20_ajo_regoff.jpeg', 1, '2026-03-09 23:00:31', '2026-03-20 06:33:11'),

(29, 1, 1,
 'Boromiel Jalea de Borojó',
 'Jalea energética de 500 g elaborada artesanalmente con pulpa de borojó (Borojoa patinoi), una fruta tropical nativa del Pacífico colombiano y ecuatoriano con excepcionalmente alta densidad calórica (62 kcal/100 g), muy elevado contenido proteico para una fruta (1,1 g/100 g), y un perfil mineral rico en fósforo, calcio, hierro y zinc. El borojó es tradicionalmente conocido como afrodisíaco y energizante natural, y su uso en la medicina tradicional chocoana y afrocolombiana está ampliamente documentado. La adición de miel de abeja pura potencia el efecto energético y reconstituyente, aportando enzimas naturales, propóleo y flavonoides con actividad antimicrobiana e inmunoestimulante. Esta jalea es una alternativa natural y funcional a los geles energéticos sintéticos para deportistas, personas con fatiga crónica o cualquiera que necesite un impulso natural de vitalidad.',
 'Consumir directamente a cucharadas (1-2 cucharadas soperas al día como energizante general), mezclar en jugos naturales, batidos de frutas o smoothies proteicos, o usar como esparcible en pan integral o galletas. Para uso deportivo, consumir 30-60 minutos antes de la actividad física. Refrigerar una vez abierto y consumir antes de 30 días. No apto para personas con alergia a la miel (proteínas apícolas).',
 '["Fuerza y Energía Natural: La alta densidad calórica del borojó combinada con los azúcares naturales de la miel proporciona energía rápida y sostenida sin los picos glucémicos de los energizantes sintéticos.", "Salud Física y Vitalidad: El fósforo del borojó es esencial para la síntesis de ATP, la molécula de energía universal; el zinc apoya la recuperación muscular post-ejercicio.", "Soporte Inmunológico: El propóleo y los flavonoides de la miel tienen actividad antibacteriana, antiviral y antiinflamatoria demostrada.", "Concentración y Agudeza Mental: El fósforo del borojó también participa en la síntesis de fosfolípidos de membrana neuronal, favoreciendo la función cognitiva.", "Alimento Funcional Ancestral: Combina el conocimiento de la medicina tradicional del Pacífico colombiano con una formulación conveniente y de alta palatabilidad."]',
 34000.00, 'img/productos/2/29_Boromil.jpeg', 1, '2026-03-09 23:00:31', '2026-03-20 06:33:11'),

(30, 1, 1,
 'K.L.G Fórmula Natural (1000 ml)',
 'Suplemento líquido vigorizante masculino de 1.000 ml elaborado con una combinación de extractos botánicos de uso tradicional en la andrología natural: maca andina negra (Lepidium meyenii var. negra), tribulus terrestris con 40% de saponinas esteroidales, ginseng coreano rojo (Panax ginseng, 7% ginsenósidos), muira puama (Ptychopetalum olacoides, el llamado "madera de potencia" de la Amazonia), damiana (Turnera diffusa) con propiedades afrodisíacas documentadas, y zinc en forma de gluconato como cofactor esencial de la síntesis de testosterona. La maca negra es la variedad con la mayor evidencia científica para mejorar la motilidad y concentración espermática, mientras que el tribulus terrestris eleva los niveles de LH (hormona luteinizante), estimulando la producción testicular de testosterona. Presentación líquida de 1.000 ml con dosificador integrado.',
 'Una copa dosificadora (30 ml) al día, preferiblemente con alimentos o 30 minutos antes de la actividad física para potenciar el rendimiento. Para efectos en vitalidad sexual y hormonal, mantener el uso continuado durante 6-8 semanas. No exceder la dosis recomendada. Consultar al médico en caso de hipertensión arterial, enfermedad cardiovascular, cáncer de próstata o tratamiento con inhibidores de la 5-fosfodiesterasa (sildenafilo). No usar en menores de 18 años.',
 '["Aumento de Energía y Resistencia: El Ginseng y la Maca negra aumentan la producción mitocondrial de energía y mejoran la resistencia aeróbica y anaeróbica.", "Mejora del Desempeño: El tribulus terrestris y la muira puama actúan sinérgicamente para mejorar el rendimiento físico y sexual.", "Salud y Vitalidad General: El zinc actúa como cofactor en más de 300 enzimas, incluyendo las de síntesis de testosterona; su aporte adecuado es fundamental para el bienestar masculino.", "Fórmula Natural: Sin aditivos sintéticos ni hormonas exógenas; todo el efecto vigorizante proviene de principios activos vegetales de eficacia documentada.", "Apoyo a la Fertilidad Masculina: La maca negra ha demostrado en estudios clínicos mejorar la motilidad espermática progresiva, la morfología y la concentración de espermatozoides."]',
