INSERT INTO `foro_hilos` (`id`, `titulo`, `contenido`, `usuario_id`, `respuestas`, `creado_en`, `actualizado_en`) VALUES
(1,
 '¿Cómo funciona GI Store? Todo lo que necesitas saber',
 'GI Store es un catálogo digital donde encuentras productos de vendedores independientes en Colombia — suplementos, tecnología, moda, hogar y más.\nEl proceso es simple:\n\n1. Exploras el catálogo y encuentras lo que te interesa.\n2. Le das clic al producto para ver detalles, precio y quién lo vende.\n3. Presionas "Comprar por WhatsApp" y quedas en contacto directo con el vendedor.\n4. Coordinan el pago y el envío entre ustedes — sin intermediarios.\n\nSin registros, sin pagos en línea, sin complicaciones.\nSi ves un producto destacado en la esquina de la pantalla, ese también es clickeable — te lleva directo a la ficha del producto.\n¿Eres vendedor y quieres publicar tus productos? Visita el portal de vendedores y empieza hoy.',
 1, 0, '2026-03-21 03:28:38', '2026-03-21 03:28:38'),

(2,
 '¿Como puedo generar una publicidad para un solo producto?',
 'En la sección de ayuda vi que se podía editar un producto y descargarlo para usarlo como publicidad.\nExplica por favor.',
 2, 1, '2026-03-22 21:40:50', '2026-03-22 22:47:47');

-- ============================================================
-- 12. FORO — RESPUESTAS
-- ============================================================

INSERT INTO `foro_respuestas` (`id`, `hilo_id`, `usuario_id`, `contenido`, `creado_en`) VALUES
(1, 2, 1,
 'Hola.\nSí, para la edición de publicidad de un producto (para descargar), debes acceder en tu panel a la sección llamada "spotlight". Allí podrás encontrar todos tus productos; solo selecciona al que deseas editar. Aparecerán dos opciones: editar con IA (te genera texto llamativo del producto) o edición libre, el cual te enviará a una página donde tendrás libertad de escribir información de dicho producto, cambiar colores, insertar texto, ampliar o reducir la imagen, cambiar el tamaño de las letras y más. Al finalizar, solo debes descargar.\n\nNota: "Si quieres cambiar la foto del producto, tienes dos opciones: cambiarlo por la URL o cambiar (editando) la imagen del producto".\n\nPosdata: dentro de la sección de edición libre, si das clic en editar libre, se abrirá una nueva ventana con todo limpio, solo esperando que tú llenes la información a tu gusto.\n\n--- Tener presente: Las imágenes solo se aceptan por URLs ---',
 '2026-03-22 22:47:47');

COMMIT;
